INSERT INTO public.photos VALUES (21069, 'Coso Alto 1871', '"Arco erigido en el Coso por el comercio en loor de S. M.", 1871. Dibujo alusivo al viaje de Amadeo I de Saboya a Zaragoza en 1871. Vemos un ef├¡mero arco conmemorativo en el Coso Alto, con uno de los torreones de la Audiencia al fondo.', 1871, 1871, 1871, 'Siglo XIX', 'CENTRO', 41.65378700, -0.88358800, '0101000020E6100000E46A64575A46ECBF65C6DB4AAFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19011201652.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19011201652.webp', 'https://www.flickr.com/photos/zaragozaantigua/19011201652/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25169, 'Calle Galo Ponte 1980', 'Dibujo centrado en los restos del esquinero edificio entre la calle de Galo Ponte, antigua de la Audiencia, y m├ís antigua Subida de los Gigantes, y un despejado Coso alto, a la derecha. Justo a la izquierda, algunos balcones de la Audiencia, junto a la que el autor ha tomado los apuntes del natural. Desde ese momento, y hasta la fecha, el derribo se ha completado felizmente, y el solar sigue en productivo barbecho inmobiliario, a la espera de tiempos nuevos, tiempos salvajes.', 1980, 1980, 1980, 'Anos 80', 'CENTRO', 41.65381300, -0.88334600, '0101000020E610000064ADA1D45E44ECBF8E59F624B0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32501628372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32501628372.webp', 'https://www.flickr.com/photos/zaragozaantigua/32501628372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25703, 'Iglesia de Santiago c.1974', 'Iglesia de Santiago desde la plaza de Salamero. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65253500, -0.88478600, '0101000020E61000004FADBEBA2A50ECBF683F524486D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22805590719.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22805590719.webp', 'https://www.flickr.com/photos/zaragozaantigua/22805590719/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25713, 'General Sanjurjo 1976', 'Imagen de la antigua calle del General Sanjurjo, luego parte de la gran avenida de C├®sar Augusto como moderno sumatorio vial para tr├ífico rodado, adem├ís, de las antiguas calles de Cerd├ín, Escuelas P├¡as, Azoque, una parte de Capit├ín Portol├®s, la plaza de San Ildefonso, y algunas bocacalles, como Ser├│n. Destaca por su soledad moment├ínea, a la derecha, la mole de un gran hotel con su gran medianera como privilegiada plataforma publicitaria, y a la izquierda, la fachada del luego tristemente c├®lebre Gran Teatro Fleta, y el acceso a la plaza de Salamero, antigua de Santa Fe. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65220200, -0.88521300, '0101000020E61000003ECF9F36AA53ECBF6231EA5A7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30386624885.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30386624885.webp', 'https://www.flickr.com/photos/zaragozaantigua/30386624885/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22994, 'Museo Pablo Serrano a├▒os 90', 'Vista a├®rea del entorno de los antiguos Talleres del Hogar Pignatelli (desde 1994 "Fundaci├│n Museo Pablo Serrano", y desde 1995, "Instituto Aragon├®s de Arte y Cultura Contempor├íneos Pablo Serrano"), en el paseo de Mar├¡a Agust├¡n 20. Fuente visual: www.facebook.com/photo.php?fbid=542402152581479&set=p...', 1990, 1990, 1999, 'Anos 90', 'CENTRO', 41.65157300, -0.89006500, '0101000020E6100000410E4A98697BECBF72FA7ABE66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22141678588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22141678588.webp', 'https://www.flickr.com/photos/zaragozaantigua/22141678588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23256, 'F├íbrica de regaliz Tur c.1900', 'Vista de la entrada de la f├íbrica de regaliz Flor, Carenou y Tur en la calle Asalto de Zaragoza, entre el actual parque Corral de la Le├▒a y el r├¡o Huerva. En primer plano, la acequia que pasaba entre los terrenos que fueron viveros y almac├®n de abastos del ej├®rcito, y la factor├¡a. A la derecha, consulado franc├®s de Zaragoza. Fuente: www.facebook.com/photo.php?fbid=635699779865162&set=g...', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64863900, -0.87183600, '0101000020E6100000F0366F9C14E6EBBF80F44D9A06D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21134866226.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21134866226.webp', 'https://www.flickr.com/photos/zaragozaantigua/21134866226/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21816, 'Pl. de la Constituci├│n a├▒os 30', 'Grupo de ciudadanos al sol de la plaza de la Constituci├│n, apostados en los vanos del Caf├® Gambrinus. A la izquierda, la Diputaci├│n Provincial. Fuente: www.facebook.com/photo.php?fbid=10206629484601419&set...', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65234100, -0.88153600, '0101000020E61000009BE447FC8A35ECBF836BEEE87FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31117803651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31117803651.webp', 'https://www.flickr.com/photos/zaragozaantigua/31117803651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21958, 'P.┬║ Independencia a├▒os 40', 'Paseo de la Independencia en los primeros a├▒os 40. A la derecha, calle de San Miguel y Restaurante Peninsular. Al fondo, plaza de Espa├▒a. Fuente: Instant├íneas zaragozanas, CAZAR, 1982.', 1940, 1940, 1949, 'Anos 40', 'CENTRO', 41.65124500, -0.88181400, '0101000020E61000004DF564FED137ECBF7E5704FF5BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20075070438.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20075070438.webp', 'https://www.flickr.com/photos/zaragozaantigua/20075070438/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22549, 'P.┬║ de la Independencia c.1972', 'Postal nocturna del paseo de la Independencia, con la plaza de Espa├▒a al fondo, cuando sus r├│tulos de ne├│n, y el reci├®n inaugurado edificio de Galer├¡as Preciados (1971) iluminando el entorno. Esta empresa fue adquirida en 1995 por otra empresa enga├▒osamente de corte ingl├®s. Fuente visual: www.delcampe.net/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65106600, -0.88166500, '0101000020E610000011E4A0849936ECBFCEC4742156D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15023110161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15023110161.webp', 'https://www.flickr.com/photos/zaragozaantigua/15023110161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25125, 'Zaragoza 1809', 'Louis-Albert-Guislain (Bar├│n de Bacler D''Albe), y Godefroy Engelmann, Ca. 1830. "Fais-toi vieille, nous ne sommes pas des ogres: Des soldats fran├ºais touillaient dans les ruines de Sarragosse, ils trouvent deux enfants cach├®s sous une voute et perissant de faim. Ils leur donnet leurs vivres." Durante las guerras peninsulares de 1808-1809, el militar franc├®s Louis-Albert-Guislain visita Espa├▒a en dos ocasiones. La primera (abril-mayo 1808), como responsable del "Cabinet Topographique de lÔÇÖEmpereur". La segunda, acompa├▒ando a Napole├│n durante la campa├▒a de noviembre 1808-enero 1809. En ellas, realiza croquis de los lugares recorridos, observa escenas y escucha el relato de algunos de los protagonistas. Con esta informaci├│n, prepara una obra gr├ífica que publicar├í posteriormente, con grabados de escenas a la moda rom├íntica (ruinas y elementos arquitect├│nicos, vegetaci├│n...) que, como en este caso, incluye una singular muestra de propaganda al estilo de la de los Sitios, pero desde la trinchera contraria (una especie de "agitprop contraSitial"). As├¡, el descriptivo t├¡tulo "Mira, anciana, no somos ogros", introduce un intento de humanizar a las tropas francesas que sitiaban primero, y ocuparon despu├®s, la ciudad de Zaragoza. Al probable relato oral de los soldados implicados, se suma la expl├¡cita voluntad pol├¡tica en reflejarlo gr├íficamente para la posteridad, convenientemente escenificado. As├¡, en un desolado paisaje urbano de ruinas y escombros no identificados (┬┐cerca del convento de San Francisco?), unos soldados imperiales se topan con dos fam├®licos ni├▒os a los que dan sus propios v├¡veres, mientras la probable madre de las criaturas gesticula entre asustada y agradecida. Se trata de una imagen muy querida en la iconograf├¡a p├║blica de todos los ej├®rcitos ocupantes: la pl├ística, oficial y condescendiente benignidad castrense para con los ind├¡genas civiles de los territorios ocupados, una vez derrotados. En este caso, adem├ís, tras una doble derrota: las dos ocupaciones ', 1809, 1809, 1809, 'Siglo XIX', 'CENTRO', 41.65202200, -0.88126700, '0101000020E6100000B66801DA5633ECBFE222F77475D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16093613925.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16093613925.webp', 'https://www.flickr.com/photos/zaragozaantigua/16093613925/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
