INSERT INTO public.photos VALUES (21436, 'Arco de San Roque 1911', 'Foto: Grasa. Unos cuantos guardias civiles custodian desde la plazuela de San Roque los inmuebles y el arco hom├│nimo, durante la huelga general revolucionaria del verano de 1911. Al fondo, el restaurante del Hotel Oriente, en el Coso Alto. Fuente: Revista Blanco y Negro, 24-9-1911.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.65319900, -0.88277900, '0101000020E6100000060FD3BEB93FECBFD4635B069CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40166715840.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40166715840.webp', 'https://www.flickr.com/photos/zaragozaantigua/40166715840/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21877, 'Calle Alfonso a├▒os 30', 'Vista del chafl├ín del caf├® Moderno, entre el Coso Alto y la calle de Alfonso I, a la derecha. Fuente: HA.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65321800, -0.88223200, '0101000020E61000006F826F9A3E3BECBF4B94BDA59CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43890526765.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43890526765.webp', 'https://www.flickr.com/photos/zaragozaantigua/43890526765/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22596, 'Calle Azoque 1970', 'Imagen circunstancial de la calle Azoque, y de la plaza de N┬¬ S┬¬ del Carmen. La intenci├│n del fot├│grafo era capturar el vallado solar chaflanero entre el minimalista callej├│n de San Jer├│nimo y la plaza, antes de que fuera construido: un pedazo de la antigua Morer├¡a que cambiaba de aspecto. Desde luego que lo consigui├│, como tambi├®n plasmar uno de los escasos testimonios gr├íficos de algunos de los edificios de la antigua plaza del Carmen, de finales del siglo XVIII, aunque su planta b├ísica lo fuera del XV y XVI. As├¡, aparece un pedazo del antiguo complejo del Convento-Colegio de las Recogidas, un a├▒o antes de que las Carmelitas Terciarias, que lo gestionaban, se unieran a las Carmelitas Misioneras Teresianas. A su lado, el n┬║ 5 de la plaza ya era una reciente mutaci├│n desarrollista, en la que lo que no ten├¡a de ancho, lo estir├│ en vertical como si fuera material pl├ístico. El n┬║ 8 manten├¡a a├║n una digna veteran├¡a. Y en el n┬║ 9, esquinera con la antigua calle Juego de la Pelota, la joya que fuera antigua casa del siglo XVII de don Eugenio Samper, profundamente remodelada en el XVIII, y que a finales de siglo era de Pedro Cort├®s y Larraz, Arzobispo de Guatemala que termin├│ siendo Obispo de Tortosa, por lo que esta casa desde entonces era conocida como "del Obispo". Su planta, imponente fachada y amplio patio interior dejaban claro que se trataba de una "casona" de esas que dicen que Zaragoza ten├¡a tantas. Por sus paredes transcurrieron interesantes historias locales, hasta que sus ultim├¡simos propietarios decidieron aplicarle la piqueta para levantar sobre su solar la cosa que hoy hay. El exterminio de los edificios dieciochescos ("viejos", "antiguallas", "caducos") fue radical y concienzudo: s├│lo quedan las fotos. Fuente visual: Archivo Municipal. Gerardo Sancho Ramo. Noviembre 1970.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65113400, -0.88457100, '0101000020E610000036AE7FD7674EECBF26A8E15B58D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17511061076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17511061076.webp', 'https://www.flickr.com/photos/zaragozaantigua/17511061076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
