INSERT INTO public.photos VALUES (25235, 'Plaza de Para├¡so 2008', 'Toma de la plaza de Para├¡so y su fuente central en 2008, antes de que en 2011 se remodelase para dar paso al tranv├¡a. Fuente: Wikipedia.', 2008, 2008, 2008, 'Siglo XXI', 'CENTRO', 41.64710100, -0.88565600, '0101000020E6100000983270404B57ECBFBD1AA034D4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15011999188.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15011999188.webp', 'https://www.flickr.com/photos/zaragozaantigua/15011999188/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
