INSERT INTO public.photos VALUES (23518, 'Coso Alto 1936', 'Desfile por el Coso Alto, a la altura del arco de San Roque, de miembros de "Acci├│n Ciudadana" de Zaragoza, organizaci├│n paramilitar de la derecha extrema local fundada para mantener el nuevo orden establecido tras el golpe del 18-19 de julio de 1936.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65332700, -0.88266300, '0101000020E6100000B874CC79C63EECBF014C1938A0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30727341530.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30727341530.webp', 'https://www.flickr.com/photos/zaragozaantigua/30727341530/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24489, 'Paseo Independencia 1971', 'Postal publicitaria de los grandes almacenes Galer├¡as Preciados, inaugurados en 1971 en el paseo de la Independencia 11. En 1995, este comercio pas├│ a ser propiedad de su competidor, El Corte Ingl├®s. Fuente visual: www.zaragozaayeryhoy.com/', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.65115700, -0.88192200, '0101000020E6100000E5EE737CB438ECBFDEC7D11C59D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24796603875.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24796603875.webp', 'https://www.flickr.com/photos/zaragozaantigua/24796603875/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25368, 'P┬║ de la Independencia c.1916', 'Imagen capturada en el bulevar del paseo de la Independencia posiblemente un festivo d├¡a. Al fondo, el Quiosco de la M├║sica emplazado originalmente en el recinto de la exposici├│n Hispano-Francesa de 1908, trasladado al paseo en 1912 a la altura de las calles de C├ídiz (a la izquierda) y la de Jer├│nimo Zurita (a la derecha). Desde entonces vertebr├│ el paseo hasta su vuelta a la plaza de Castelar en 1927.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.65110200, -0.88215700, '0101000020E6100000C5FF1D51A13AECBF1B2E724F57D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51019362787.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51019362787.webp', 'https://www.flickr.com/photos/zaragozaantigua/51019362787/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21495, 'Cabezo de Buenavista 1923', 'AHPZ. Gabriel Faci. 1923. "Paisaje nevado." La nieve ca├¡da difumina los contornos, suaviza el paisaje. Con la nieve tambi├®n se precipita un silencio dif├¡cil de definir. Todo es distinto. Mientras un tremendo temporal pasaba por encima del Reino de Espa├▒a, en el primero de los inviernos de la Dictadura de Primo de Rivera, gente curiosa se iba al sur, donde estaba proyectado hacer un gran parque, al que tendr├¡a que conducir un nuevo y moderno vial denominado "Gran V├¡a", sobre un cubierto r├¡o Huerva. Pero la cosa estaba bastante parada. De momento, s├│lo estaban garantizadas las buenas vistas desde el Cabezo. Abajo, entre la nieve, una leve vista del oscuro cauce de la acequia de las Adulas, contorne├índose desde su toma de agua del Canal, muy cerca de donde cinco a├▒os despu├®s se levantar├í el Rinc├│n de Goya. Otra l├¡nea de ├írboles, un poco m├ís al fondo, se├▒ala el cauce del Huerva.', 1923, 1923, 1923, 'Anos 20', 'UNIVERSIDAD', 41.63133000, -0.89516000, '0101000020E6100000DAFE959526A5ECBFE97DE36BCFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15270757968.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15270757968.webp', 'https://www.flickr.com/photos/zaragozaantigua/15270757968/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21578, 'Puente de Santa Isabel c.1923', 'Paso de carro con cuadr├║pedos, proveniente del barrio de Santa Isabel, transitando por el puente de Santa Isabel sobre el r├¡o G├íllego en direcci├│n a Zaragoza. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1923, 1923, 1923, 'Anos 20', 'EL RABAL', 41.67108200, -0.84225800, '0101000020E6100000766B990CC7F3EABF9677D503E6D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24276819414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24276819414.webp', 'https://www.flickr.com/photos/zaragozaantigua/24276819414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
