INSERT INTO public.photos VALUES (24805, 'Estaci├│n del Norte 2011', 'Recreaci├│n infogr├ífica del proyecto de Olano y Mendo Arquitectos para el entorno de la Estaci├│n del Norte, en 2011. En el centro, la calle de Perdiguera. Al fondo, la Seo sin chapitel y el Pilar. No se ejecut├│. Fuente: www.facebook.com/Olano-y-Mendo-Arquitectos-SLP-1624010171...', 2011, 2011, 2011, 'Siglo XXI', 'EL RABAL', 41.66012900, -0.87193600, '0101000020E6100000D28F8653E6E6EBBF1212691B7FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33660909496.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33660909496.webp', 'https://www.flickr.com/photos/zaragozaantigua/33660909496/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
