INSERT INTO public.photos VALUES (22381, 'Vista a├®rea Casablanca 1964', 'Vista a├®rea parcial del barrio de Casablanca, con el Canal Imperial al fondo, el Stadium Casablanca, la V├¡a Ib├®rica, la subestaci├│n de El├®ctricas Reunidas derribada en agosto de 2016... En primer t├®rmino, campos de cultivo. Fuente: Colecci├│n Rafael Margal├®.', 1964, 1964, 1964, 'Anos 60', 'CASABLANCA', 41.62551300, -0.90523600, '0101000020E6100000ED2DE57CB1F7ECBF861C5BCF10D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22316448195.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22316448195.webp', 'https://www.flickr.com/photos/zaragozaantigua/22316448195/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23401, 'Valdespartera 2006', 'Vista a├®rea del barrio de Valdespartera de Zaragoza, en abril de 2006. La zona est├í urbanizada ya, para cometer el atentado urbano hoy perpetrado. Fuente: Zaragoza 1908-2008. FCC.', 2006, 2006, 2006, 'Siglo XXI', 'CASABLANCA', 41.62082500, -0.92026700, '0101000020E610000028D192C7D372EDBF05C58F3177CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15091522363.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15091522363.webp', 'https://www.flickr.com/photos/zaragozaantigua/15091522363/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23431, 'C.┬¬ de Valencia 1911', 'Imagen capturada durante la intensa nevada que el d├¡a 14 de enero de 1911 cubri├│ con un manto blanco la ciudad de Zaragoza. El fot├│grafo Freudenthal centra su objetivo en la Fuente de los Incr├®dulos en su tradicional ubicaci├│n junto a la carretera de Valencia e inmediata al apeadero de la l├¡nea del ferrocarril de Cari├▒ena, que en la imagen queda a la izquierda y fuera de plano.', 1911, 1911, 1911, 'Anos 10', 'CASABLANCA', 41.62857100, -0.90794900, '0101000020E6100000EDF2AD0FEB0DEDBF651BB80375D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51774835206.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51774835206.webp', 'https://www.flickr.com/photos/zaragozaantigua/51774835206/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22187, 'Parque Primo de Rivera 1959', 'Posado en el monumento a la Exposici├│n Hispano-Francesa de 1908 de los miembros del Club Ciclista Iberia, antes de la salida de una excursi├│n. Este club deportivo naci├│ en 1924 como Secci├│n Ciclista del Iberia Sport Club, pasando a ser independiente en 1934. Fuente: www.clubciclistaiberia.com', 1959, 1959, 1959, 'Anos 50', 'CASABLANCA', 41.63061300, -0.89634200, '0101000020E6100000DAFF006BD5AEECBF5AB741EDB7D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32071550314.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32071550314.webp', 'https://www.flickr.com/photos/zaragozaantigua/32071550314/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25181, 'Seminario Metropolitano 1943', 'Dibujo incluido en el anteproyecto del nuevo Seminario Metropolitano de Zaragoza firmado por Santiago Lagunas Mayand├¡a, Casimiro Lanaja Bel y Manuel Mart├¡nez de Ubago, inspirado en formas historicistas neorrom├ínicas y neog├│ticas, y con capacidad para 400 aspirantes a sacerdotes. En 1945 su coloc├│ su primera piedra, y ser├¡a inaugurado en 1952.', 1943, 1943, 1943, 'Anos 40', 'CASABLANCA', 41.63586000, -0.91004100, '0101000020E6100000C39CA04D0E1FEDBFD36A48DC63D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49414491933.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49414491933.webp', 'https://www.flickr.com/photos/zaragozaantigua/49414491933/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24843, 'Canal Imperial 1922', 'Imagen capturada en la orilla norte del tramo del Canal Imperial de Arag├│n, desde el camino que en paralelo transcurre a la altura de Valdefierro, e inmediatamente anterior al denominado Puente-Acueducto de la Acequia del Medio que, de iguales dimensiones que el de Pedrola, conduce agua del r├¡o Huerva y que originalmente abastec├¡a a las acequias del Medio, del Plano y del Brazal del Fierro.', 1922, 1922, 1922, 'Anos 20', 'CASABLANCA', 41.63503400, -0.92681000, '0101000020E61000006362F3716DA8EDBF8DEC4ACB48D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51940704552.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51940704552.webp', 'https://www.flickr.com/photos/zaragozaantigua/51940704552/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25938, 'Graveras de La Paz 1977', 'Esta es una de esas tremendas im├ígenes que era posible captar en el guetto de las "Graveras", de las "Chabolas", porque sus denominaciones eran varias (y la mayor parte, denigrantes) en lo que hoy es el Parque de La Paz. La denominaci├│n de "graveras" respond├¡a al hecho de ser, desde antiguo, lugares de extracci├│n de ├íridos ("grava") para obras. Desde los a├▒os 50 del pasado esta zona se convirti├│ en un asentamiento de chabolas, hasta 1979, cuando, con la recuperaci├│n de la democracia, desde el Ayuntamiento se exploraron f├│rmulas, algunas de ellas muy problem├íticas, err├íticas, y mejorables, para darle una soluci├│n a esta indignidad, felizmente superada, aunque chabolas sigue habiendo en la ciudad. Hubo que esperar a 1982 para ver transformarse esta zona en lo que hoy es. El objetivo fotogr├ífico nos sit├║a en un elevado punto, en la actual parte alta de la Rotonda Villa de Pau, desde el que podemos vislumbrar el Puente de San Viator sobre el Canal, a la derecha. De la Pasarela peatonal met├ílica del mismo nombre s├│lo se aprecia el arranque. La imponente mole de la f├íbrica "ALUMALSA" queda al otro lado del Canal, adem├ís de edificios tan representativos como la Escuela Julio Cejador Frauca, y el Convento de las Monjas del Casal, con su caracter├¡stica espada├▒a. Al fondo, emergiendo t├¡midamente del tejado de "ALUMALSA", apenas vemos el remate de la neocl├ísica c├║pula de la iglesia de San Fernando. Justo a continuaci├│n, los tremebundos macrobloques de la acera izquierda de Terrazas de Cu├®llar-Pintor Mar├¡n Bag├╝├®s, que dejan como enanitos a los m├ís veteranos conjuntos de la acera derecha. Fuente visual: "La evoluci├│n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'TORRERO', 41.62865100, -0.87869700, '0101000020E610000069FCC22B491EECBF81CCCEA277D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14855646151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14855646151.webp', 'https://www.flickr.com/photos/zaragozaantigua/14855646151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22350, 'Stadium Venecia c.1968', 'Foto: Colecci├│n Sergio Joven. Vista a├®rea del Stadium Venecia, en la calle Fray Juli├ín Garc├®s del barrio de Torrero. Promovido por Acci├│n Cat├│lica, fue inaugurado en 1966. Fuente: rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'TORRERO', 41.62519300, -0.89005400, '0101000020E61000004791B586527BECBF1558005306D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20531256240.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20531256240.webp', 'https://www.flickr.com/photos/zaragozaantigua/20531256240/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24908, 'Fosa Com├║n 1919', 'Foto Cepero. Reci├®n instalado mausoleo del escultor Jos├® Bueno para la fosa com├║n del cementerio cat├│lico de Torrero de Zaragoza. Fuente: La Esfera, 12 de julio de 1919.', 1919, 1919, 1919, 'Anos 10', 'TORRERO', 41.62159800, -0.88347000, '0101000020E610000068E89FE06245ECBF27A1F48590CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20029364152.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20029364152.webp', 'https://www.flickr.com/photos/zaragozaantigua/20029364152/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25942, 'Plaza de las Canteras 1984', 'Foto Arturo Burgos, 1984. Vista de la plaza de las Canteras del barrio de Torrero, tomada desde el inicio de la calle de Fray Juli├ín Garc├®s. Al fondo, la avenida de Am├®rica. Fuente: Zaragoza, sus calles y su historia, 1984.', 1984, 1984, 1984, 'Anos 80', 'TORRERO', 41.63173700, -0.88547300, '0101000020E610000056B60F79CB55ECBF2A560DC2DCD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18812265184.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18812265184.webp', 'https://www.flickr.com/photos/zaragozaantigua/18812265184/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25947, 'Cementerio c.1920', 'Vista del interior del cementerio de Torrero, con su entrada al fondo. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1920, 1920, 1920, 'Anos 20', 'TORRERO', 41.62272000, -0.88770700, '0101000020E6100000CAC4AD821868ECBF5648F949B5CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24618952160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24618952160.webp', 'https://www.flickr.com/photos/zaragozaantigua/24618952160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25957, 'Pinares de Venecia 1996', 'En el mes de marzo de 1996 se realiz├│ una acampada en los terrenos de los Pinares de Venecia por los que estaba proyectado que pasase el Tercer Cintur├│n de ronda de la ciudad. Particip├│ m├ís de un millar de personas, convocadas por la Coordinadora Venecia-Torrero-La Paz contra el Tercer Cintur├│n, con los lemas de ÔÇ£No al Tercer Cintur├│nÔÇØ y ÔÇ£Salvemos el pinar, salvemos el CanalÔÇØ, que ofrec├¡a un trazado alternativo menos agresivo con el entorno. En la imagen, parte de los acampados ensaya acciones de resistencia pasiva para el caso de que comiencen las obras. Al final, el trazado alternativo fue desestimado y la nueva v├¡a pas├│ por donde estaba previsto, a partir de 2003.', 1996, 1996, 1996, 'Anos 90', 'TORRERO', 41.62461100, -0.89255300, '0101000020E6100000454B1E4FCB8FECBF66DCD440F3CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50367967793.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50367967793.webp', 'https://www.flickr.com/photos/zaragozaantigua/50367967793/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25944, 'Cabezo Cortado 1978', 'El Cabezo Cortado ha sido el mirador natural del barrio desde que gravas, arenas y arcillas, producto de la sedimentaci├│n del Ebro, se dispusieron durante el Terciario en una terraza de varios metros de espesor sobre yesos y limos, y conformaron una elevaci├│n desde la que la vista de la ciudad era estupenda. ├ôleos, apuntes, fotograf├¡as, incluso documentales, han surgido de la contemplaci├│n desde su cumbre. Esto era lo normal. Esta imagen no hace eso, y enfoca justo al otro lado, hacia el Canal Imperial, su ribera, y el Barrio de la Paz. En primer t├®rmino, llaman la atenci├│n los humanos grupos entre los pinos de la ladera, como si se tratase de un parque o zona verde al uso. Ya no se ven estas cosas desde hace tiempo, desde que se dej├│ degradar el Cabezo hasta su actual situaci├│n, en que da mucha penica. Con un poco de voluntad pol├¡tica se pod├¡a adecentar y dignificar, sin mucho costo. Ser├¡a, adem├ís, una buena pedagog├¡a porque, aun en los tiempos del wifi, el tuiter, del face, del ipod, del..., es minor├¡a quien conoce esta zona. Al otro lado del Canal, imagen del Colegio de San Viator y la continuidad de las "Graveras" cuando eran consideradas por ciertos sectores como peor que adentrarse en territorio sioux (en el supuesto, adem├ís, de que ser sioux fuera malo). A este lado del Canal, muy al fondo, las moles de los bloques de otras Terrazas, la de Pina, hoy Cu├®llar, y los restos de la f├íbrica Alumalsa. Casi ya fuera de plano, a la derecha, los bloques de la peculiar urbanizaci├│n de la parcela de la calle Melilla n┬║ 28, reci├®n estrenaditos. Hac├¡a apenas un a├▒o, no muy lejos de aqu├¡, un polic├¡a armada hab├¡a disparado de muerte a un obrero en paro por hacer una pintada que dec├¡a "Trabajo s├¡ Polic├¡a no", y un esbozo de hoz y martillo. Una calle cercana lleva desde hace no mucho el nombre del asesinado: Miguel Vicente Basanta L├│pez. Fuente visual: "La evoluci├│n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1978, 1978, 1978, 'Anos 70', 'TORRERO', 41.63025500, -0.87297300, '0101000020E6100000F04FA91265EFEBBFFB912232ACD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20076476729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20076476729.webp', 'https://www.flickr.com/photos/zaragozaantigua/20076476729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22109, 'Tudor 1953', 'A├®rea vista de la Factor├¡a de la Sociedad Espa├▒ola del Acumulador Tudor, en las enormes y recientes instalaciones de la carretera de Navarra donde estaba ubicada desde 1946. As├¡ ser├í hasta 1989. En la parte inferior, sobre la carretera de Logro├▒o, el puente de paso del ferrocarril de Caminreal. Un segundo puente, m├ís inmediato, se qued├│ en inacabado proyecto de "bypass" de conexi├│n hacia Casetas. Fuente visual: Arxiu Nacional de Catalunya.', 1953, 1953, 1953, 'Anos 50', 'OLIVER-VALDEFIERRO', 41.65974100, -0.92102300, '0101000020E610000051A4FB390579EDBF486AA16472D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21979037130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21979037130.webp', 'https://www.flickr.com/photos/zaragozaantigua/21979037130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24830, 'Calle de San Vicente Ferrer a├▒os 60', 'Calle de San Vicente Ferrer en el barrio del Oliver de Zaragoza. A la izquierda, murete del colegio p├║blico Fernando el Cat├│lico. Al fondo, peque├▒as edificaciones que a├║n siguen en pie en 2014 en la calle de Antonio de Leyva. Fuente: www.facebook.com/photo.php?fbid=10203293020151893&set...', 1960, 1960, 1969, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.65135800, -0.92685000, '0101000020E6100000F085C954C1A8EDBF76FEEDB25FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15307175656.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15307175656.webp', 'https://www.flickr.com/photos/zaragozaantigua/15307175656/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22771, 'Ctra. de Madrid 1979', 'Editorial Luis Vives en sus nuevas instalaciones dise├▒adas por Joaqu├¡n Maggioni Casadevall en la carretera de Madrid km 315,700. Al fondo, verde entorno del Barrio Oliver que m├ís adelante ser├í adecuado como hom├│nimo parque, tambi├®n llamado del Oeste. A la derecha, el Centro Santo ├üngel de Atades, inaugurado en 1969. Fuera de plano y hacia la derecha, el reformatorio El Buen Pastor, con el que confrontaba al otro lado de la carretera.', 1979, 1979, 1979, 'Anos 70', 'OLIVER-VALDEFIERRO', 41.64648600, -0.93328900, '0101000020E6100000EEED96E480DDEDBF33A9A10DC0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33537238213.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33537238213.webp', 'https://www.flickr.com/photos/zaragozaantigua/33537238213/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21735, 'Vista a├®rea y humo c.1931', 'Vista a├®rea con la Industrial Qu├¡mica en primer plano, echando humo. Abajo a la derecha, la Aljafer├¡a, y sobre ├®sta la plaza de toros. El r├¡o Ebro, a la izquierda, es cruzado por el puente del Ferrocarril de la Almozara. Al fondo, el puente de Piedra y el Pilar. Entre el humo, la torre de San Pablo y la c├║pula de Santiago. Arriba a la izquierda, el r├¡o G├íllego.', 1931, 1931, 1931, 'Anos 30', 'LA ALMOZARA', 41.66104500, -0.89517500, '0101000020E6100000304CA60A46A5ECBF9817601F9DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21385980869.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21385980869.webp', 'https://www.flickr.com/photos/zaragozaantigua/21385980869/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22755, 'C.┬║ de la Almozara 1978', 'Interesante imagen del oficioso aparcadero intermodal habilitado a la entrada del literal camino de la Almozara, capturada a la altura de la calle de Monegros (a la izquierda), con el fondo del moderno bloque del paseo de M┬¬ Agust├¡n chaflanero con la calle de Santa Luc├¡a. Al fondo, a la derecha, edificios del complejo de la Compa├▒├¡a Industrial Agr├¡cola, recayentes al mar de v├¡as y a la Industrial Qu├¡mica. Fuente visual: Banco de Im├ígenes/Asociaci├│n de Vecinos Barrio de San Jos├®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'LA ALMOZARA', 41.66026600, -0.89518000, '0101000020E6100000A110018750A5ECBF9354A69883D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32748624250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32748624250.webp', 'https://www.flickr.com/photos/zaragozaantigua/32748624250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23085, 'Pabell├│n de Espa├▒a 2007', 'Construcci├│n del Pabell├│n de Espa├▒a de la Expo 2008 de Zaragoza, obra de Francisco "Patxi" Mangado. Fuente: picasaweb.google.com/CHELUYS', 2007, 2007, 2007, 'Siglo XXI', 'LA ALMOZARA', 41.66859700, -0.89802600, '0101000020E610000072A59E05A1BCECBF139A249694D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19345835593.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19345835593.webp', 'https://www.flickr.com/photos/zaragozaantigua/19345835593/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24550, 'La Qu├¡mica c.1978', 'Apartadero ferroviario de La Industrial Qu├¡mica de Zaragoza. A la derecha, el edificio de piensos CIA que ser├í derribado en 1992. Fondo Biblioteca Rafael Andolz.', 1978, 1978, 1978, 'Anos 70', 'LA ALMOZARA', 41.65840100, -0.89569400, '0101000020E61000004A26A77686A9ECBFAC53E57B46D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14941626071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14941626071.webp', 'https://www.flickr.com/photos/zaragozaantigua/14941626071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26054, 'Avenida Tenor Fleta 1984', 'Foto: Tom├ís Mora Ruata. Vista de la avenida del Tenor Fleta, con el colegio de los Agustinos al fondo y la entrada de la calle de Uncastillo a la derecha. Fuente: www.facebook.com/photo.php?fbid=1536701036358009&set=...', 1984, 1984, 1984, 'Anos 80', 'SAN JOS├ë', 41.63962200, -0.88073400, '0101000020E61000005D35CF11F92EECBFACE63922DFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32253731215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32253731215.webp', 'https://www.flickr.com/photos/zaragozaantigua/32253731215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24457, 'Camino de San Jos├® 1925', 'Talleres del yesaire y decorador Enrique Cubero. Edificio obra de Francisco Albi├▒ana, en el antiguo camino de San Jos├® 155. Fuente: La Esfera 609, 1925.', 1925, 1925, 1925, 'Anos 20', 'SAN JOS├ë', 41.63579500, -0.87930400, '0101000020E610000055BE67244223ECBFECFA05BB61D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19604893413.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19604893413.webp', 'https://www.flickr.com/photos/zaragozaantigua/19604893413/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25759, 'Jard├¡n de la Memoria 1992', 'Imagen en altura, capturada desde los altos bloques de la calle pintor Mar├¡n Bag├╝├®s, posiblemente su n├║mero 8, con el aspecto del reci├®n inaugurado "Parque de la Memoria", en el barrio de San Jos├®. Estos aterrazados terrenos formaron parte de las extensas instalaciones de la antigua f├íbrica textil de D├ímaso Pina, y tras su derribo, fueron calificadas como espacio edificable para levantar necesarios rascacielos. La presi├│n vecinal para conseguir que esto fuera una zona verde, con notables dificultades, largos a├▒os de lucha, y demediado resultado, hall├│ eco municipal, hasta llegar al resultado de la imagen. El terrible solanar, con el natural crecimiento de los nuevos ├írboles, configura un espacio interior de apariencia hoy bien distinta, m├ís amable. Sobre el acusado desnivel del terreno, y con una ins├│lita atenci├│n a los requerimientos vecinales del momento, se actu├│ definiendo una serie de referencias emblem├íticas y representativas de la historia del barrio: entre otros, y en primer t├®rmino, el monumento a la "Ba├▒ista", de Carlos Ochoa, el estanque de "Cantarranas", y un recuerdo del trazado de la antigua acequia de Ontanar, tres fogonazos del pasado ligado al agua, a las desaparecidas acequias al aire, sus "ba├▒os", y al derribado lavadero de la Balseta. A su lado, los primeros huertos urbanos de la ciudad, cuando eso a├║n se consideraba nost├ílgico "ocio de viejos", un mini parque tem├ítico de lo provinciano. Detr├ís hay un enorme espacio vac├¡o, convertido en plaza, donde deber├¡a estar la chimenea de la antigua f├íbrica textil, pero que fue derribada con alevos├¡a y nocturnidad, cuando esas cosas viejas no se valoraban demasiado. A la derecha, la calle de Joaqu├¡n Sorolla, y al fondo, las traseras de la calle Garc├¡a Lorca. Fuente visual: Revista "Nuestra Zaragoza", Ayuntamiento de Zaragoza.', 1992, 1992, 1992, 'Anos 90', 'SAN JOS├ë', 41.63353700, -0.87923700, '0101000020E610000062DC0DA2B522ECBF29E78BBD17D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27460993726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27460993726.webp', 'https://www.flickr.com/photos/zaragozaantigua/27460993726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22714, 'Vista Miguel Servet 1970', 'Vista a├®rea de la calle de Miguel Servet y su entorno, desde las inmediaciones de la estaci├│n de Utrillas (fuera de plano). En el centro de la imagen, el Matadero. M├ís arriba, el cuartel de San Jos├® y el resto de la ciudad consolidada, con el Pilar. Fuente: www.facebook.com/photo.php?fbid=10208503253957120&set...', 1970, 1970, 1970, 'Anos 70', 'SAN JOS├ë', 41.64356200, -0.86952000, '0101000020E610000033F9669B1BD3EBBF6479573D60D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29670696426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29670696426.webp', 'https://www.flickr.com/photos/zaragozaantigua/29670696426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24396, 'Miguel Servet c.1960', 'Imagen de una maqueta que representa el antiguo colegio de La Salle Montemol├¡n en su esquinera ubicaci├│n entre el camino de las Torres (izquierda), y la calle de Miguel Servet (derecha), en cuyo n├║mero 36 ten├¡a radicada su direcci├│n postal y entrada principal. Tras unos a├▒os de provisional estancia en una casa de las inmediaciones ("casa de Policeto", desde 1909, como Colegio de Nuestra Se├▒ora del Pilar), en 1916 fue inaugurado este centro, con nueva planta proyectada por Francisco Albi├▒ana, autor del bloque central en forma h├¡brida de "T-L", con formas y aires neomud├®jares, casi racionalistas. Ten├¡a inmediata vecindad con la "Fundici├│n de Iranzo" (la construcci├│n que chaflanea el principio del camino de las Torres), y al otro lado de Miguel Servet quedaba la Harinera del Pilar, y el cuartel de Intendencia de San Jos├®. Pose├¡a el colegio dos peque├▒os patios donde la soberan├¡a del baloncesto era notable, a los que luego se a├▒adi├│ el gran patio del fondo, junto a la calle de la Concepci├│n, resultado del encementamiento de una antigua zona de huertos. En 1929 mud├│ su denominaci├│n por la de Colegio La Salle Montemol├¡n. El curso 1971-1972 fue el ├║ltimo en estas instalaciones, y el siguiente de 1972-1973 fue el pionero en las nov├¡simas aulas de la calle Jos├® Galiay, frente a la antigua Granja Agr├¡cola, donde mantuvo en su nombre de forma descontextualizada el "Montemol├¡n" de sus or├¡genes en lugar de actualizarlo por el de "Miraflores" de su nueva ubicaci├│n, al estilo de los Lakers tras dejar Minnesota y r4esidenciarse en Los ├üngeles. El colegio de la imagen fue vendido, derribado, y sobre ├®l fue levantada una de esas renombradas modernidades habitacionales de las que esta ciudad tanto se enorgullece. Fuente visual: "Memoria Escolar 1971-1972", amable aportaci├│n de Juan Carlos Crespo.', 1960, 1960, 1960, 'Anos 60', 'SAN JOS├ë', 41.64714000, -0.87386400, '0101000020E610000016DBA4A2B1F6EBBF7BF7C77BD5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26134908475.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26134908475.webp', 'https://www.flickr.com/photos/zaragozaantigua/26134908475/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
